-- Ensure (company_id, employee_number) is unique so ON CONFLICT works.
-- Postgres treats NULLs as distinct in unique indexes by default,
-- so existing rows with NULL employee_number won't block this.
CREATE UNIQUE INDEX IF NOT EXISTS uq_employees_company_empno
  ON employees (company_id, employee_number);

DO $$
DECLARE
  v_company_id uuid;
BEGIN
  -- Single-tenant: pick the first company. If you have multiple,
  -- replace with: SELECT id INTO v_company_id FROM companies WHERE slug = 'your-slug';
  SELECT id INTO v_company_id FROM companies ORDER BY created_at LIMIT 1;
  IF v_company_id IS NULL THEN
    RAISE EXCEPTION 'No company found. Run /setup first.';
  END IF;

  -- 1. Upsert departments referenced in the import

  -- 2. Upsert employees
  -- Each row uses (company_id, employee_number) as the natural key.

Santol St. cor Magsaysay, Brgy 586

Permanent - 503 Garcia St. Poblacion, Plaridel, Bulacan', '586', 'Sampaloc', 'Metro Manila', '1992-02-27'::date, 'married', true) ON CONFLICT (company_id, employee_number) DO UPDATE SET name = EXCLUDED.name, first_name = EXCLUDED.first_name, middle_name = EXCLUDED.middle_name, last_name = EXCLUDED.last_name, position_title = EXCLUDED.position_title, role = EXCLUDED.role, department = EXCLUDED.department, department_id = EXCLUDED.department_id, employment_status = EXCLUDED.employment_status, hire_date = EXCLUDED.hire_date, sss_number = COALESCE(EXCLUDED.sss_number, employees.sss_number), tin_number = COALESCE(EXCLUDED.tin_number, employees.tin_number), pagibig_number = COALESCE(EXCLUDED.pagibig_number, employees.pagibig_number), philhealth_number = COALESCE(EXCLUDED.philhealth_number, employees.philhealth_number), gender = COALESCE(EXCLUDED.gender, employees.gender), nationality = COALESCE(EXCLUDED.nationality, employees.nationality), work_email = COALESCE(EXCLUDED.work_email, employees.work_email), personal_email = COALESCE(EXCLUDED.personal_email, employees.personal_email), phone = COALESCE(EXCLUDED.phone, employees.phone), address_line1 = COALESCE(EXCLUDED.address_line1, employees.address_line1), address_line2 = COALESCE(EXCLUDED.address_line2, employees.address_line2), city = COALESCE(EXCLUDED.city, employees.city), province = COALESCE(EXCLUDED.province, employees.province), date_of_birth = COALESCE(EXCLUDED.date_of_birth, employees.date_of_birth), civil_status = COALESCE(EXCLUDED.civil_status, employees.civil_status), active = true;
8602 Sgt. Yabut St., Guadalupe Nuevo, Makati City, 1212', 'Calaca', 'Batangas', 'Batangas', '1989-06-26'::date, 'single', true) ON CONFLICT (company_id, employee_number) DO UPDATE SET name = EXCLUDED.name, first_name = EXCLUDED.first_name, middle_name = EXCLUDED.middle_name, last_name = EXCLUDED.last_name, position_title = EXCLUDED.position_title, role = EXCLUDED.role, department = EXCLUDED.department, department_id = EXCLUDED.department_id, employment_status = EXCLUDED.employment_status, hire_date = EXCLUDED.hire_date, sss_number = COALESCE(EXCLUDED.sss_number, employees.sss_number), tin_number = COALESCE(EXCLUDED.tin_number, employees.tin_number), pagibig_number = COALESCE(EXCLUDED.pagibig_number, employees.pagibig_number), philhealth_number = COALESCE(EXCLUDED.philhealth_number, employees.philhealth_number), gender = COALESCE(EXCLUDED.gender, employees.gender), nationality = COALESCE(EXCLUDED.nationality, employees.nationality), work_email = COALESCE(EXCLUDED.work_email, employees.work_email), personal_email = COALESCE(EXCLUDED.personal_email, employees.personal_email), phone = COALESCE(EXCLUDED.phone, employees.phone), address_line1 = COALESCE(EXCLUDED.address_line1, employees.address_line1), address_line2 = COALESCE(EXCLUDED.address_line2, employees.address_line2), city = COALESCE(EXCLUDED.city, employees.city), province = COALESCE(EXCLUDED.province, employees.province), date_of_birth = COALESCE(EXCLUDED.date_of_birth, employees.date_of_birth), civil_status = COALESCE(EXCLUDED.civil_status, employees.civil_status), active = true;

  RAISE NOTICE 'Imported % active employees', 51;
